CREATE POLICY "twilio_tts_no_anon_select" ON storage.objects FOR SELECT TO anon, authenticated USING (bucket_id = 'twilio-tts' AND false);
CREATE POLICY "twilio_tts_no_anon_insert" ON storage.objects FOR INSERT TO anon, authenticated WITH CHECK (bucket_id = 'twilio-tts' AND false);
CREATE POLICY "twilio_tts_no_anon_update" ON storage.objects FOR UPDATE TO anon, authenticated USING (bucket_id = 'twilio-tts' AND false) WITH CHECK (bucket_id = 'twilio-tts' AND false);
CREATE POLICY "twilio_tts_no_anon_delete" ON storage.objects FOR DELETE TO anon, authenticated USING (bucket_id = 'twilio-tts' AND false);